def solve(board):
    rows = [set() for _ in range(9)]
    cols = [set() for _ in range(9)]
    boxes = [set() for _ in range(9)]
    empty = []
    for r in range(9):
        for c in range(9):
            if board[r][c] != '.':
                d = board[r][c]
                rows[r].add(d); cols[c].add(d); boxes[(r//3)*3+c//3].add(d)
            else:
                empty.append((r, c))
    def bt(idx):
        if idx == len(empty): return True
        r, c = empty[idx]
        box = (r//3)*3+c//3
        for d in '123456789':
            if d not in rows[r] and d not in cols[c] and d not in boxes[box]:
                board[r][c] = d; rows[r].add(d); cols[c].add(d); boxes[box].add(d)
                if bt(idx+1): return True
                board[r][c] = '.'; rows[r].discard(d); cols[c].discard(d); boxes[box].discard(d)
        return False
    bt(0)
    return '\n'.join(''.join(row) for row in board)

